module top_module(
    input [7:0] parity_x,
    output reg z
    );task calc_even_parity;
        input [7:0] parity_x;
        output z;
        begin
            z = parity_x[7]^parity_x[6]^parity_x[5]^parity_x[4]^parity_x[3]^parity_x[2]^parity_x[1]^parity_x[0];
        end
    endtask
    always
        @ (parity_x)
        begin
            calc_even_parity(parity_x,z);
        end

endmodule
